nswer\") or data.get(\"answer\") or output_part.get(\"actual_answer\") or output_part.get(\"answer\") or input_part.get(\"actual_answer\") or input_part.get(\"answer\") or nested_input.get(\"actual_answer\") or nested_input.get(\"answer\") or nested_input.get(\"system_answer\") or nested_input.get(\"candidate_answer\") or \"\"\n        golden_answer = data.get(\"golden_answer\") or data.get(\"gold_answer\") or reference_part.get(\"golden_answer\") or reference_part.get(\"gold_answer\") or reference_part.get(\"answer\") or reference_part.get(\"actual_answer\") or input_part.get(\"golden_answer\") or input_part.get(\"gold_answer\") or nested_input.get(\"golden_answer\") or nested_input.get(\"gold_answer\") or \"\"\n        # 结构化参考（如 {年龄/健康状况/推荐险种: ...}）没有 golden_answer/answer 文本键时，\n        # 把整个 reference 序列化为 golden_answer 文本，避免 qa_gold_answer 场景误判 missing_golden_answer。\n        if not golden_answer and reference_part:\n            golden_answer = json.dumps(reference_part, ensure_ascii=False)\n        for key in self.metadata_fields:\n            if key in data and key not in metadata:\n                metadata[key] = data[key]\n            if key in input_part and key not in metadata:\n                metadata[key] = input_part[key]\n        if data.get(\"case_id\") and \"case_id\" not in metadata:\n            metadata[\"case_id\"] = data[\"case_id\"]\n        contexts = self._normalize_contexts(contexts)\n        sample = {\n            \"input\": {\"question\": str(question), \"contexts\": contexts},\n            \"output\": {\"actual_answer\": str(actual_answer)},\n            \"reference\": {\"golden_answer\": str(golden_answer)} if golden_answer else {},\n            \"metadata\": metadata,\n            \"scenario\": str(data.get(\"scenario\") or self._infer_scenario(question, actual_answer, golden_answer, contexts)),\n            \"data_quality_flags\": [],\n        }\n        sample[\"data_quality_flags\"] = self._quality_flags(sample)\n        return sample\n\n    def _normalize_contexts(self, contexts):\n        if contexts is None or contexts == \"\":\n            return []\n        if isinstance(contexts, list):\n            return contexts\n        return [contexts]\n\n    def _infer_scenario(self, question, actual_answer, golden_answer, contexts):\n        if golden_answer:\n            return \"qa_gold_answer\"\n        if contexts:\n            return \"qa_context_faithfulness\"\n        if question and actual_answer:\n            return \"qa_weak_quality\"\n        return \"invalid_sample\"\n\n    def _quality_flags(self, sample):\n        flags = []\n        if not sample[\"input\"].get(\"question\"):\n            flags.append(\"missing_question\")\n        if not sample[\"output\"].get(\"actual_answer\"):\n            flags.append(\"missing_actual_answer\")\n        scenario = sample.get(\"scenario\")\n        if scenario == \"qa_gold_answer\" and not sample.get(\"reference\", {}).get(\"golden_answer\"):\n            flags.append(\"missing_golden_answer\")\n        if scenario == \"qa_context_faithfulness\" and not sample[\"input\"].get(\"contexts\"):\n            flags.append(\"missing_contexts\")\n        if scenario == \"qa_weak_quality\":\n            flags.append(\"estimated_quality_only\")\n        return flags", "status": "ok", "tool_name": "search_source_file"}]}, "judge": {"actual": {"actual_answer": "您需要准备身份证、银行卡、住院发票和费用清单，然后在我们APP上提交就行。"}, "boundary_decision": {"reasoning": "评估仅基于提供的golden_answer和actual answer，信息完整，无不可控限制。", "within_evaluable_scope": "true"}, "business_expectations": [{"acceptance_criteria": ["实际答案中提到的材料项数量和质量与金标准答案中的必要项目（理赔申请书、身份证、银行卡、发票、费用明细清单、出院小结/诊断证明、社保结算单）一一对应，缺少任一必要项即视为未通过"], "downstream_consumer": "准备报销材料的用户", "evidence_refs": [{"reference": "golden_answer", "type": "qa_sample_boundary"}], "expectation_id": "报销材料清单完整且无遗漏", "expected_outcome": "答案包含上述所有材料项，无重大遗漏", "priority": "highest", "user_intent": "明确所有需要准备的材料"}, {"acceptance_criteria": ["实际答案中包含身份证正反面复印件、诊断证明需盖章、银行卡